import java.sql.*;

public class SQLInjectionSecure {
    public static void main(String[] args) {
        try {
            String userInput = "admin'; DROP TABLE users; --"; // Malicious input simulating SQL Injection

            // Connect to the database
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Create a parameterized SQL query
            String sql = "SELECT * FROM users WHERE username = ?";
            PreparedStatement statement = conn.prepareStatement(sql);

            // Set the user input as a parameter in the prepared statement
            statement.setString(1, userInput);

            // Execute the prepared statement (no need to concatenate user input)
            ResultSet resultSet = statement.executeQuery();

            // Process the result set (not shown for brevity)

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

